import React, { useEffect, useState } from 'react';
import jwtDecode from 'jwt-decode';

const clientId = 'YOUR_CLIENT_ID';
const redirectUri = 'http://localhost:3000/callback';
const authorizationEndpoint = 'https://your-authorization-server.com/auth';
const tokenEndpoint = 'https://your-authorization-server.com/token';

function App() {
  const [user, setUser] = useState(null);

  useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');

    if (code) {
      fetch(tokenEndpoint, {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: new URLSearchParams({
          grant_type: 'authorization_code',
          code,
          redirect_uri: redirectUri,
          client_id: clientId,
        }),
      })
        .then(response => response.json())
        .then(data => {
          const idToken = data.id_token;
          const userProfile = jwtDecode(idToken);
          setUser(userProfile);
        })
        .catch(error => console.error('Error fetching tokens:', error));
    }
  }, []);

  const login = () => {
    window.location.href = `${authorizationEndpoint}?response_type=code&client_id=${clientId}&redirect_uri=${redirectUri}`;
  };

  return (
    <div>
      {user ? (
        <div>
          <h1>Welcome, {user.name}</h1>
          <p>Email: {user.email}</p>
        </div>
      ) : (
        <button onClick={login}>Login</button>
      )}
    </div>
  );
}

export default App;